// Build a single Telegram HTML message. Telegram (unlike WhatsApp)
// has no template approval — we can ship rich multi-line markup with
// bold section headers and arbitrary newlines.
//
// Sections:
//   1. Per-order detail — multi-line per customer with attached add-ons.
//   2. Aggregate roll-up — single-line dish totals per meal.
//   3. Notes — critical ⚠️ first, regular after.
//   4. Ingredient procurement — split by lunch / dinner so prep stations
//      can portion separately without mental math.

const data = $input.first().json;

const esc = (s) => String(s ?? '无')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const lunchCount = data.lunch?.count ?? 0;
const dinnerCount = data.dinner?.count ?? 0;
const lunchOrders = esc(data.lunch?.ordersText ?? data.lunch?.summaryText);
const dinnerOrders = esc(data.dinner?.ordersText ?? data.dinner?.summaryText);
const lunchSummary = esc(data.lunch?.summaryText);
const dinnerSummary = esc(data.dinner?.summaryText);
const notesText = esc(data.notesText);
// Per-meal ingredient lists; fall back to combined ingredientText if endpoint
// hasn't been redeployed with the per-meal fields yet (defensive).
const lunchIngredients = esc(data.lunch?.ingredientText ?? data.ingredientText);
const dinnerIngredients = esc(data.dinner?.ingredientText ?? data.ingredientText);

const lines = [
  `🍳 <b>早安 BowlMama</b> — ${esc(data.date)}`,
  '',
  `🌞 <b>午餐</b> (${lunchCount} 单)`,
  '',
  lunchOrders,
  '',
  `🌙 <b>晚餐</b> (${dinnerCount} 单)`,
  '',
  dinnerOrders,
  '',
  '📊 <b>今日汇总</b>',
  `午餐：${lunchSummary}`,
  `晚餐：${dinnerSummary}`,
  '',
  '📝 <b>备注</b>',
  notesText,
  '',
  '🛒 <b>今日采购</b>',
  '',
  '🌞 <b>午餐</b>',
  lunchIngredients,
  '',
  '🌙 <b>晚餐</b>',
  dinnerIngredients,
  '',
  '—— Incredibowl 厨房系统',
];

return [{ json: { text: lines.join('\n'), _raw: data } }];

// Surface failures. Telegram returns 400 if chatId hasn't messaged the
// bot first, or 401 if token is wrong. Right now this only writes to
// the n8n execution log — swap for an email node if you want push alerts.
const err = $input.first().json;
console.error('[daily-prep-tg] Telegram send failed', JSON.stringify(err));
return [{ json: { error: err } }];
